import React, { useState } from 'react';
import { View, Text, TextInput, StyleSheet, TouchableOpacity } from 'react-native';
import { useTheme } from '../context/ThemeContext';

const ForgotPasswordScreen = ({ navigation }) => {
  const { isDark } = useTheme();
  const [email, setEmail] = useState('');

  return (
    <View style={[styles.container, { backgroundColor: isDark ? '#111827' : '#fff7ed' }]}> 
      <Text style={[styles.title, { color: isDark ? '#f97316' : '#f97316' }]}>Reset Password</Text>
      <Text style={[styles.subtitle, { color: isDark ? '#9ca3af' : '#6b7280' }]}> 
        Enter your email address and we'll send you instructions to reset your password.
      </Text>
      <TextInput
        style={[styles.input, { backgroundColor: isDark ? '#1f2937' : '#fff', color: isDark ? '#fff' : '#000' }]}
        placeholder="Email"
        value={email}
        onChangeText={setEmail}
        placeholderTextColor={isDark ? '#9ca3af' : '#6b7280'}
      />
      <TouchableOpacity style={styles.button}>
        <Text style={styles.buttonText}>Send Reset Link</Text>
      </TouchableOpacity>
      <TouchableOpacity onPress={() => navigation.goBack()}>
        <Text style={[styles.linkText, { color: isDark ? '#f97316' : '#f97316' }]}> 
          Back to Sign In
        </Text>
      </TouchableOpacity>
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 20,
    justifyContent: 'center',
  },
  title: {
    fontSize: 24,
    fontWeight: 'bold',
    marginBottom: 10,
    textAlign: 'center',
  },
  subtitle: {
    textAlign: 'center',
    marginBottom: 20,
  },
  input: {
    height: 50,
    marginVertical: 10,
    borderRadius: 8,
    padding: 15,
    borderWidth: 1,
    borderColor: '#f97316',
  },
  button: {
    backgroundColor: '#f97316',
    padding: 15,
    borderRadius: 8,
    marginVertical: 20,
  },
  buttonText: {
    color: '#fff',
    textAlign: 'center',
    fontSize: 16,
    fontWeight: 'bold',
  },
  linkText: {
    textAlign: 'center',
    marginTop: 10,
  },
});

export default ForgotPasswordScreen;
